import React from "react";
import {Link} from "react-router-dom";
import {Button, List, Table, Tooltip} from "antd";
import moment from "moment";
import * as Setting from "./Setting";
import * as OrderBackend from "./backend/OrderBackend";
import i18next from "i18next";
import BaseListPage from "./BaseListPage";
import PopconfirmModal from "./common/modal/PopconfirmModal";
import {EditOutlined} from "@ant-design/icons";

class OrderListPage extends BaseListPage {
  newOrder() {
    const randomName = Setting.getRandomName();
    const owner = Setting.getRequestOrganization(this.props.account);
    return {
      owner: owner,
      name: `order_${randomName}`,
      createdTime: moment().format(),
      displayName: `New Order - ${randomName}`,
      products: [],
      user: "",
      payment: "",
      state: "Created",
      message: "",
      startTime: moment().format(),
      endTime: "",
    };
  }

  addOrder() {
    const newOrder = this.newOrder();
    OrderBackend.addOrder(newOrder)
      .then((res) => {
        if (res.status === "ok") {
          this.props.history.push({pathname: `/orders/${newOrder.owner}/${newOrder.name}`, mode: "add"});
          Setting.showMessage("success", i18next.t("general:Successfully added"));
        } else {
          Setting.showMessage("error", `${i18next.t("general:Failed to add")}: ${res.msg}`);
        }
      })
      .catch(error => {
        Setting.showMessage("error", `${i18next.t("general:Failed to connect to server")}: ${error}`);
      });
  }

  cancelOrder(order) {
    OrderBackend.cancelOrder(order.owner, order.name)
      .then((res) => {
        if (res.status === "ok") {
          Setting.showMessage("success", i18next.t("general:Successfully canceled"));
          this.fetch({
            pagination: this.state.pagination,
          });
        } else {
          Setting.showMessage("error", `${i18next.t("general:Failed to cancel")}: ${res.msg}`);
        }
      })
      .catch(error => {
        Setting.showMessage("error", `${i18next.t("general:Failed to connect to server")}: ${error}`);
      });
  }

  deleteOrder(i) {
    OrderBackend.deleteOrder(this.state.data[i])
      .then((res) => {
        if (res.status === "ok") {
          Setting.showMessage("success", i18next.t("general:Successfully deleted"));
          this.fetch({
            pagination: {
              ...this.state.pagination,
              current: this.state.pagination.current > 1 && this.state.data.length === 1 ? this.state.pagination.current - 1 : this.state.pagination.current,
            },
          });
        } else {
          Setting.showMessage("error", `${i18next.t("general:Failed to delete")}: ${res.msg}`);
        }
      })
      .catch(error => {
        Setting.showMessage("error", `${i18next.t("general:Failed to connect to server")}: ${error}`);
      });
  }

  renderTable(orders) {
    const columns = [
      {
        title: i18next.t("general:Name"),
        dataIndex: "name",
        key: "name",
        width: "140px",
        fixed: "left",
        sorter: true,
        ...this.getColumnSearchProps("name"),
        render: (text, record, index) => {
          return (
            <Link to={`/orders/${record.owner}/${text}`}>
              {text}
            </Link>
          );
        },
      },
      {
        title: i18next.t("general:Organization"),
        dataIndex: "owner",
        key: "owner",
        width: "150px",
        sorter: true,
        ...this.getColumnSearchProps("owner"),
        render: (text, record, index) => {
          return (
            <Link to={`/organizations/${text}`}>
              {text}
            </Link>
          );
        },
      },
      {
        title: i18next.t("general:Created time"),
        dataIndex: "createdTime",
        key: "createdTime",
        width: "160px",
        sorter: true,
        render: (text, record, index) => {
          return Setting.getFormattedDate(text);
        },
      },
      {
        title: i18next.t("order:Products"),
        dataIndex: "products",
        key: "products",
        ...this.getColumnSearchProps("products"),
        render: (text, record, index) => {
          const productInfos = record?.productInfos || [];
          if (productInfos.length === 0) {
            return `(${i18next.t("general:empty")})`;
          }
          return (
            <div>
              <List
                size="small"
                locale={{emptyText: " "}}
                dataSource={productInfos}
                style={{
                  paddingTop: 8,
                  paddingBottom: 8,
                }}
                renderItem={(productInfo, i) => {
                  const price = productInfo.price * (productInfo.quantity || 1);
                  const currency = record.currency || "USD";
                  return (
                    <List.Item>
                      <div style={{display: "inline"}}>
                        <Tooltip placement="topLeft" title={i18next.t("general:Edit")}>
                          <Button style={{marginRight: "5px"}} icon={<EditOutlined />} size="small" onClick={() => Setting.goToLinkSoft(this, `/products/${record.owner}/${productInfo.name}`)} />
                        </Tooltip>
                        <Link to={`/products/${record.owner}/${productInfo.name}`}>
                          {productInfo.displayName || productInfo.name}
                        </Link>
                        <span style={{marginLeft: "8px", color: "#666"}}>
                          {Setting.getPriceDisplay(price, currency)}
                        </span>
                      </div>
                    </List.Item>
                  );
                }}
              />
            </div>
          );
        },
      },
      {
        title: i18next.t("order:Price"),
        dataIndex: "price",
        key: "price",
        width: "160px",
        sorter: true,
        ...this.getColumnSearchProps("price"),
        render: (text, record, index) => {
          const price = (record.price || 0).toFixed(2);
          const currency = record.currency || "USD";
          const priceDisplay = Setting.getPriceDisplay(price, currency);

          return record.payment ? (
            <Link to={`/payments/${record.owner}/${record.payment}`}>
              {priceDisplay}
            </Link>
          ) : (
            <span>{priceDisplay}</span>
          );
        },
      },
      {
        title: i18next.t("general:User"),
        dataIndex: "user",
        key: "user",
        width: "120px",
        sorter: true,
        ...this.getColumnSearchProps("user"),
        render: (text, record, index) => {
          if (text === "") {
            return "(empty)";
          }
          return (
            <Link to={`/users/${record.owner}/${text}`}>
              {text}
            </Link>
          );
        },
      },
      {
        title: i18next.t("general:State"),
        dataIndex: "state",
        key: "state",
        width: "120px",
        sorter: true,
        ...this.getColumnSearchProps("state"),
      },
      {
        title: i18next.t("general:Start time"),
        dataIndex: "startTime",
        key: "startTime",
        width: "160px",
        sorter: true,
        render: (text, record, index) => {
          return Setting.getFormattedDate(text);
        },
      },
      {
        title: i18next.t("general:End time"),
        dataIndex: "endTime",
        key: "endTime",
        width: "160px",
        sorter: true,
        render: (text, record, index) => {
          if (text === "") {
            return "(empty)";
          }
          return Setting.getFormattedDate(text);
        },
      },
      {
        title: i18next.t("general:Action"),
        dataIndex: "",
        key: "op",
        width: "320px",
        fixed: (Setting.isMobile()) ? "false" : "right",
        render: (text, record, index) => {
          const isAdmin = Setting.isLocalAdminUser(this.props.account);
          return (
            <div style={{display: "flex", flexWrap: "wrap", gap: "8px"}}>
              <Button onClick={() => this.props.history.push(`/orders/${record.owner}/${record.name}/pay`)}>
                {record.state === "Created" ? i18next.t("order:Pay") : i18next.t("general:Detail")}
              </Button>
              <Button danger onClick={() => this.cancelOrder(record)} disabled={record.state !== "Created" || !isAdmin}>
                {i18next.t("general:Cancel")}
              </Button>
              <Button type="primary" onClick={() => this.props.history.push({pathname: `/orders/${record.owner}/${record.name}`, mode: isAdmin ? "edit" : "view"})}>{isAdmin ? i18next.t("general:Edit") : i18next.t("general:View")}</Button>
              {isAdmin && (
                <PopconfirmModal
                  title={i18next.t("general:Sure to delete") + `: ${record.name} ?`}
                  onConfirm={() => this.deleteOrder(index)}
                >
                </PopconfirmModal>
              )}
            </div>
          );
        },
      },
    ];

    const paginationProps = {
      total: this.state.pagination.total,
      showQuickJumper: true,
      showSizeChanger: true,
      showTotal: () => i18next.t("general:{total} in total").replace("{total}", this.state.pagination.total),
    };

    return (
      <div>
        <Table scroll={{x: "max-content"}} columns={columns} dataSource={orders} rowKey={(record) => `${record.owner}/${record.name}`} size="middle" bordered pagination={paginationProps}
          title={() => {
            const isAdmin = Setting.isLocalAdminUser(this.props.account);
            return (
              <div>
                {i18next.t("general:Orders")}&nbsp;&nbsp;&nbsp;&nbsp;
                <Button type="primary" size="small" disabled={!isAdmin} onClick={this.addOrder.bind(this)}>{i18next.t("general:Add")}</Button>
              </div>
            );
          }}
          loading={this.state.loading}
          onChange={this.handleTableChange}
        />
      </div>
    );
  }

  fetch = (params = {}) => {
    const field = params.searchedColumn, value = params.searchText;
    const sortField = params.sortField, sortOrder = params.sortOrder;
    this.setState({loading: true});
    OrderBackend.getOrders(Setting.isDefaultOrganizationSelected(this.props.account) ? "" : Setting.getRequestOrganization(this.props.account), params.pagination.current, params.pagination.pageSize, field, value, sortField, sortOrder)
      .then((res) => {
        this.setState({
          loading: false,
        });
        if (res.status === "ok") {
          this.setState({
            data: res.data,
            pagination: {
              ...params.pagination,
              total: res.data2,
            },
            searchText: params.searchText,
            searchedColumn: params.searchedColumn,
          });
        } else {
          if (Setting.isResponseDenied(res)) {
            this.setState({
              isAuthorized: false,
            });
          } else {
            Setting.showMessage("error", res.msg);
          }
        }
      });
  };
}

export default OrderListPage;
